package com.socialblog.follower.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="follows",uniqueConstraints=@UniqueConstraint(name="uk_follow_pair",columnNames={"follower_id","followed_id"}))public class Follow{@Id private UUID id;@Column(name="follower_id",nullable=false)private UUID followerId;@Column(name="followed_id",nullable=false)private UUID followedId;@Column(name="created_at",nullable=false)private Instant createdAt;protected Follow(){}public Follow(UUID follower,UUID followed){id=UUID.randomUUID();followerId=follower;followedId=followed;createdAt=Instant.now();}public UUID getId(){return id;}public UUID getFollowerId(){return followerId;}public UUID getFollowedId(){return followedId;}public Instant getCreatedAt(){return createdAt;}}
